export const getListBlockersUrl = (dealId: string,
    params?: ListBlockersParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/v1/deals/${dealId}/blockers?${stringifiedParams}` : `/api/v1/deals/${dealId}/blockers`
}

